import hashlib
import secrets
from cryptography.fernet import Fernet

def encrypt_sensitive_data(data, encryption_key=None):
    """
    Encrypts sensitive user data before storing it in the database.
    
    Args:
        data (str): The sensitive data to encrypt
        encryption_key (bytes, optional): The encryption key to use. 
                                         If None, a new key will be generated.
    
    Returns:
        tuple: (encrypted_data, encryption_key) where encrypted_data is the 
               encrypted data and encryption_key is the key used for encryption
    """
    if encryption_key is None:
        encryption_key = Fernet.generate_key()
    
    f = Fernet(encryption_key)
    encrypted_data = f.encrypt(data.encode())
    
    return encrypted_data, encryption_key

def hash_sensitive_data(data, salt=None):
    """
    Hashes sensitive user data for comparison purposes.
    
    Args:
        data (str): The sensitive data to hash
        salt (str, optional): Salt to use for hashing. If None, a random salt is generated.
    
    Returns:
        tuple: (hashed_data, salt) where hashed_data is the hashed data and salt is the salt used
    """
    if salt is None:
        salt = secrets.token_hex(16)
    
    salted_data = data + salt
    hashed_data = hashlib.sha256(salted_data.encode()).hexdigest()
    
    return hashed_data, salt